// Input: { orderId, amount, method }
// Calls: paymentService.confirmPayment()
// Updates payment_status: PartiallyPaid / Paid
// If Paid: auto-transition order to 'Paid' status
const { confirmPayment } = require('./app/js/orders/paymentService.js');
const { sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { orderId, amount, method } = $input.first().json;
const result = confirmPayment(orderId, { amount, method });
await sendManagerAlert(`💰 Оплата ${orderId}: ${amount} грн (${method}) — статус: ${result.payment_status}`);
return [{ json: result }];

// Input: { orderId }
// Calls: deliveryService.markReadyForPickup()
// Sends notification to client
const { markReadyForPickup } = require('./app/js/orders/deliveryService.js');
const { sendClientMessage, sendManagerAlert } = require('./app/js/tasks/notificationService.js');
const { orderId, clientId } = $input.first().json;
markReadyForPickup(orderId);
if (clientId) await sendClientMessage(clientId, `✅ Ваше замовлення ${orderId} готове до видачі!`);
await sendManagerAlert(`✅ Замовлення ${orderId} готове.`);
return $input.all();

// Calls: deliveryService.confirmPickup()
// Consumes reserved stock
// Sets status to PickedUp
const { confirmPickup } = require('./app/js/orders/deliveryService.js');
const { sendClientMessage } = require('./app/js/tasks/notificationService.js');
const { orderId, clientId } = $input.first().json;
confirmPickup(orderId);
if (clientId) await sendClientMessage(clientId, `📦 Замовлення ${orderId} видано. Дякуємо!`);
return $input.all();

// Input: { orderId, trackingNumber, carrier }
// Calls: deliveryService.markShipped()
// Sends tracking info to client
const { markShipped } = require('./app/js/orders/deliveryService.js');
const { sendClientMessage } = require('./app/js/tasks/notificationService.js');
const { orderId, clientId, trackingNumber, carrier } = $input.first().json;
markShipped(orderId, { trackingNumber, carrier });
if (clientId) {
  const msg = `📬 Ваше замовлення ${orderId} відправлено.${trackingNumber ? ` Трек: ${trackingNumber}` : ''}`;
  await sendClientMessage(clientId, msg);
}
return $input.all();
